import React from 'react';
import './Home.css';

const Home = ({ onProceed }) => {
  return (
    <div className="home-hero">
      <div className="overlay" />
      <div className="content">
        <p className="eyebrow">Centralized Employee Document Management System</p>
        <h1>Welcome to Centralized Employee Document Management System</h1>
        <p className="subtext">Secure, fast, centralized HR document automation</p>
        <button className="primary-btn" onClick={onProceed}>
          Proceed to Login
        </button>
      </div>
      <footer>© {new Date().getFullYear()} Centralized Employee Document Management System. All rights reserved.</footer>
    </div>
  );
};

export default Home;
